INSERT INTO `pertanyaan` (`id`, `pertanyaan`, `jenis`, `created_at`, `updated_at`, `bagian`) VALUES
(1, 'Mengatur ulang hal-hal di sekitar Anda sehingga masalah Anda sangat berpeluang terselesaikan.', 'Pemecahan Masalah', NULL, NULL, 'I'),
(2, 'Menetapkan beberapa tujuan bagi diri Anda untuk menghadapi situasi.', 'Pemecahan Masalah', NULL, NULL, 'I'),
(3, 'Mempertimbangkan pilihan Anda dengan sangat hati-hati.', 'Pemecahan Masalah', NULL, NULL, 'I'),
(4, 'Mencoba berbagai cara untuk menyelesaikan masalah hingga Anda menemukan satu cara yang berhasil.', 'Pemecahan Masalah', NULL, NULL, 'I'),
(5, 'Memfokuskan perhatian Anda sepenuhnya untuk memecahkan masalah.', 'Pemecahan Masalah', NULL, NULL, 'I'),
(6, 'Menyusun rencana tindakan dalam pikiran Anda.', 'Pemecahan Masalah', NULL, NULL, 'I'),
(7, 'Tetap tegar dan berusaha keras meraih apa yang Anda inginkan dalam situasi yang sedang dihadapi', 'Pemecahan Masalah', NULL, NULL, 'I'),
(8, 'Mencoba memecahkan masalah.', 'Pemecahan Masalah', NULL, NULL, 'I'),
(9, 'Mengungkapkan perasaan pada teman.', 'Dukungan Sosial', NULL, NULL, 'I'),
(10, 'Berbicara dengan orang lain tentang situasi yang dihadapi, karena membicarakannya membantu Anda merasa lebih baik.', 'Dukungan Sosial', NULL, NULL, 'I'),
(11, 'Mengungkapkan ketakutan dan kekhawatiran Anda kepada teman atau kerabat.', 'Dukungan Sosial', NULL, NULL, 'I'),
(12, 'Menemui seseorang (teman atau profesional) untuk membantu Anda merasa lebih baik.', 'Dukungan Sosial', NULL, NULL, 'I'),
(13, 'Menemui teman untuk membantu Anda merasa lebih baik tentang masalahnya.', 'Dukungan Sosial', NULL, NULL, 'I'),
(14, 'Menemui teman untuk meminta nasihat tentang cara mengubah situasi.', 'Dukungan Sosial', NULL, NULL, 'I'),
(15, 'Mencari kepastian dari orang-orang yang mengenal Anda dengan sangat baik.', 'Dukungan Sosial', NULL, NULL, 'I'),
(16, 'Menghabiskan lebih banyak waktu dari biasanya dengan menyendiri.', 'Penghindaran', NULL, NULL, 'I'),
(17, 'Menghindari berkumpul bersama orangorang pada umumnya.', 'Penghindaran', NULL, NULL, 'I'),
(18, 'Berfantasi tentang bagaimana hal bisa berbeda.', 'Penghindaran', NULL, NULL, 'I'),
(19, 'Menyamakan diri dengan karakter novel atau film.', 'Penghindaran', NULL, NULL, 'I'),
(20, 'Ketika saya dihadapkan pada situasi yang penuh tekanan, saya memikirkannya dengan cara yang membantu saya tetap tenang.', 'Penilaian Ulang', NULL, NULL, 'II'),
(21, 'Ketika saya ingin merasakan emosi yang lebih positif, saya mengubah cara saya memikirkan situasi.', 'Penilaian Ulang', NULL, NULL, 'II'),
(22, 'Saya mengendalikan emosi dengan cara memikirkan situasi yang sedang saya hadapi.', 'Penilaian Ulang', NULL, NULL, 'II'),
(23, 'Ketika saya ingin merasakan emosi yang sedikit lebih negatif, saya mengubah cara memikirkan situasi yang saya hadapi.', 'Penilaian Ulang', NULL, NULL, 'II'),
(24, 'Memikirkan betapa sulitnya berkonsentrasi.', 'Perenungan', NULL, NULL, 'III'),
(25, 'Memikirkan betapa pasif dan tidak termotivasinya perasaan Anda.', 'Perenungan', NULL, NULL, 'III'),
(26, 'Memikirkan bagaimana Anda tidak merasakan apa-apa lagi.', 'Perenungan', NULL, NULL, 'III'),
(27, 'Memikirkan bagaimana anda tidak merasa bersemangat untuk melakukan sesuatu.', 'Perenungan', NULL, NULL, 'III'),
(28, 'Memikirkan semua kekurangan, kegagalan, kesalahan Anda.', 'Perenungan', NULL, NULL, 'III'),
(29, 'Mencoba menemukan sesuatu yang positif dalam situasi atau sesuatu yang Anda pelajari.', 'Pengalihan', NULL, NULL, 'III'),
(30, 'Berpikir “Saya akan melakukan sesuatu untuk membuat diri saya merasa lebih baik.”', 'Pengalihan', NULL, NULL, 'III'),
(31, 'Melakukan sesuatu yang menyenangkan dengan seorang teman.', 'Pengalihan', NULL, NULL, 'III'),
(32, 'Saya menerima perasaan menyenangkan.', 'Penerimaan perasaan menyenangkan', NULL, NULL, 'IV'),
(33, 'Saya berusaha mempertahankan perasaan menyenangkan selama saya bisa.', 'Penerimaan perasaan menyenangkan', NULL, NULL, 'IV'),
(34, 'Ketika saya mengalami perasaan menyenangkan, saya dapat menerimanya.', 'Penerimaan perasaan menyenangkan', NULL, NULL, 'IV'),
(35, 'Dipenuhi Perasaan Menyenangkan Membuat Saya Bahagia', 'Penerimaan perasaan menyenangkan', NULL, NULL, 'IV'),
(36, 'Saya bertahan dengan perasaan menyenangkan.', 'Penerimaan perasaan menyenangkan', NULL, NULL, 'IV'),
(37, 'Saya menikmati perasaan positif sebanyak yang saya bisa.', 'Penerimaan perasaan menyenangkan', NULL, NULL, 'IV'),
(38, 'Saya mencoba merasakan perasaan menyenangkan sebisa mungkin', 'Penerimaan perasaan menyenangkan', NULL, NULL, 'IV'),
(39, 'Saya mencoba segalanya untuk memperkuat perasaan menyenangkan', 'Penerimaan perasaan menyenangkan', NULL, NULL, 'IV'),
(40, 'Ketika saya mengalami perasaan menyenangkan, saya mencoba untuk memperkuatnya.', 'Penerimaan perasaan menyenangkan', NULL, NULL, 'IV');
